import java.io.*;
import java.util.*;

public class Main {
    static class Edge {
        int to;
        int w;
        Edge(int to, int w) { this.to = to; this.w = w; }
    }
    static class Node implements Comparable<Node> {
        int v;
        long dist;
        Node(int v, long dist) { this.v = v; this.dist = dist; }
        public int compareTo(Node o) { return Long.compare(this.dist, o.dist); }
    }
    // Fast scanner reading tokens irrespective of line breaks
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        private int skip() throws IOException {
            int c;
            while ((c = readByte()) != -1) {
                if (c > ' ') return c;
            }
            return -1;
        }
        int nextInt() throws IOException {
            int c = skip();
            int sign = 1;
            if (c == '-' ) { sign = -1; c = readByte(); }
            int val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            @SuppressWarnings("unchecked")
            ArrayList<Edge>[] adj = new ArrayList[N];
            for (int i = 0; i < N; i++) adj[i] = new ArrayList<>();
            for (int i = 0; i < M; i++) {
                int u = fs.nextInt() - 1;
                int v = fs.nextInt() - 1;
                int w = fs.nextInt();
                adj[u].add(new Edge(v, w));
                adj[v].add(new Edge(u, w));
            }
            long INF = Long.MAX_VALUE / 4;
            long[] dist = new long[N];
            Arrays.fill(dist, INF);
            dist[0] = 0;
            boolean[] visited = new boolean[N];
            PriorityQueue<Node> pq = new PriorityQueue<>();
            pq.add(new Node(0, 0));
            while (!pq.isEmpty()) {
                Node cur = pq.poll();
                int u = cur.v;
                if (visited[u]) continue;
                visited[u] = true;
                for (Edge e : adj[u]) {
                    int v = e.to;
                    long nd = dist[u] + e.w;
                    if (nd < dist[v]) {
                        dist[v] = nd;
                        pq.add(new Node(v, nd));
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                if (dist[i] == INF) out.append(-1);
                else out.append(dist[i]);
                if (i + 1 < N) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

